import{_ as t,o as s,c as i,ag as e}from"./chunks/framework.DEqXEGcv.js";const k=JSON.parse('{"title":"NAS 镜像安装","description":"","frontmatter":{},"headers":[],"relativePath":"zh/docs/guide/nas.md","filePath":"zh/docs/guide/nas.md"}'),l={name:"zh/docs/guide/nas.md"};function r(n,a,d,o,h,p){return s(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="nas-镜像安装" tabindex="-1">NAS 镜像安装 <a class="header-anchor" href="#nas-镜像安装" aria-label="Permalink to &quot;NAS 镜像安装&quot;">​</a></h1><p>RDE 提供基于 <strong>Debian 13</strong> 构建的 ISO 镜像，可将任意 x86_64 主机变成功能完整的 NAS + 云桌面。</p><h2 id="与-curl-部署的区别" tabindex="-1">与 curl 部署的区别 <a class="header-anchor" href="#与-curl-部署的区别" aria-label="Permalink to &quot;与 curl 部署的区别&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>curl / deb 部署</th><th>NAS ISO 镜像</th></tr></thead><tbody><tr><td><strong>基础系统</strong></td><td>需已有 Ubuntu / Debian</td><td>自带完整 Debian 13 系统</td></tr><tr><td><strong>依赖</strong></td><td>需通过网络安装部分依赖</td><td>全部预装，开箱即用</td></tr><tr><td><strong>Flatpak</strong></td><td>首次运行需 setup 安装依赖</td><td>已预装，无需额外 setup</td></tr><tr><td><strong>适用场景</strong></td><td>已有云服务器 / VPS</td><td>全新硬件 / 旧电脑改 NAS</td></tr><tr><td><strong>安装方式</strong></td><td>一行命令</td><td>U 盘启动安装</td></tr></tbody></table><h2 id="下载" tabindex="-1">下载 <a class="header-anchor" href="#下载" aria-label="Permalink to &quot;下载&quot;">​</a></h2><a href="https://pan.baidu.com/s/1lCf0dcNp8RSKK6COtzGcRw?pwd=rde1" target="_blank" style="display:inline-flex;align-items:center;gap:0.5rem;padding:0.6rem 1.5rem;background:linear-gradient(135deg, #4F46E5, #7C3AED);color:white;border-radius:8px;text-decoration:none;font-weight:600;"> 📥 百度网盘下载 </a><p>提取码：<code>rde1</code></p><h2 id="系统要求" tabindex="-1">系统要求 <a class="header-anchor" href="#系统要求" aria-label="Permalink to &quot;系统要求&quot;">​</a></h2><ul><li><strong>CPU</strong>: x86_64 架构（Intel / AMD）</li><li><strong>内存</strong>: 最低 2GB，推荐 4GB+</li><li><strong>磁盘</strong>: 最低 16GB，推荐 64GB+ SSD</li><li><strong>网络</strong>: 有线网络连接</li></ul><h2 id="安装步骤" tabindex="-1">安装步骤 <a class="header-anchor" href="#安装步骤" aria-label="Permalink to &quot;安装步骤&quot;">​</a></h2><h3 id="_1-制作启动-u-盘" tabindex="-1">1. 制作启动 U 盘 <a class="header-anchor" href="#_1-制作启动-u-盘" aria-label="Permalink to &quot;1. 制作启动 U 盘&quot;">​</a></h3><p>准备一个 4GB 以上的 U 盘，使用以下工具将 ISO 写入：</p><p><strong>Windows:</strong></p><ul><li><a href="https://rufus.ie/" target="_blank" rel="noreferrer">Rufus</a> — 选择 ISO 文件，分区类型选 GPT，点击开始</li><li><a href="https://www.ventoy.net/" target="_blank" rel="noreferrer">Ventoy</a> — 安装 Ventoy 后，直接把 ISO 复制到 U 盘即可</li></ul><p><strong>Linux / macOS:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查找 U 盘设备名（如 /dev/sdb）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsblk</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 写入 ISO（注意替换设备名，会清除 U 盘所有数据）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> if=rde-os.iso</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> of=/dev/sdX</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bs=4M</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status=progress</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sync</span></span></code></pre></div><h3 id="_2-bios-设置" tabindex="-1">2. BIOS 设置 <a class="header-anchor" href="#_2-bios-设置" aria-label="Permalink to &quot;2. BIOS 设置&quot;">​</a></h3><ol><li>插入 U 盘，开机按 <code>F2</code> / <code>F12</code> / <code>Del</code> 进入 BIOS</li><li>设置 U 盘为第一启动项</li><li>保存退出，自动从 U 盘启动</li></ol><h3 id="_3-安装系统" tabindex="-1">3. 安装系统 <a class="header-anchor" href="#_3-安装系统" aria-label="Permalink to &quot;3. 安装系统&quot;">​</a></h3><p>按照 Debian 安装向导完成系统安装。安装完成后重启，RDE 桌面会自动启动。</p><h3 id="_4-访问桌面" tabindex="-1">4. 访问桌面 <a class="header-anchor" href="#_4-访问桌面" aria-label="Permalink to &quot;4. 访问桌面&quot;">​</a></h3><p>在浏览器中访问 <code>http://&lt;NAS_IP&gt;:3080</code> 即可进入 RDE 桌面。</p><h2 id="预装内容" tabindex="-1">预装内容 <a class="header-anchor" href="#预装内容" aria-label="Permalink to &quot;预装内容&quot;">​</a></h2><p>ISO 镜像相比 curl 部署版本，额外预装了：</p><ul><li><strong>Flatpak 运行环境</strong>：直接安装 Flatpak 应用，无需 setup</li><li><strong>完整系统依赖</strong>：所有 RDE 依赖的系统库和工具</li><li><strong>硬盘管理工具</strong>：方便 NAS 场景下管理多硬盘</li><li><strong>网络配置工具</strong>：静态 IP、网桥等 NAS 常用网络配置</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="安装后如何更新-rde" tabindex="-1">安装后如何更新 RDE？ <a class="header-anchor" href="#安装后如何更新-rde" aria-label="Permalink to &quot;安装后如何更新 RDE？&quot;">​</a></h3><p>ISO 安装的 RDE 可以通过 deb 包更新：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/ruizi-store/rde/releases/latest/download/rde_latest_amd64.deb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./rde_latest_amd64.deb</span></span></code></pre></div><h3 id="能否在虚拟机中体验" tabindex="-1">能否在虚拟机中体验？ <a class="header-anchor" href="#能否在虚拟机中体验" aria-label="Permalink to &quot;能否在虚拟机中体验？&quot;">​</a></h3><p>可以。在 VMware / VirtualBox / Proxmox 中创建虚拟机，挂载 ISO 安装即可。推荐分配 2 核 4GB 内存。</p><h3 id="与群晖-飞牛有什么区别" tabindex="-1">与群晖 / 飞牛有什么区别？ <a class="header-anchor" href="#与群晖-飞牛有什么区别" aria-label="Permalink to &quot;与群晖 / 飞牛有什么区别？&quot;">​</a></h3><p>RDE 是开源的 Web 桌面方案，可运行在任意 x86 硬件上。相比群晖和飞牛：</p><ul><li>完全开源，无授权限制</li><li>内置 Docker 应用商店</li><li>Web 桌面体验，不仅是 NAS 管理界面</li></ul>`,34)])])}const g=t(l,[["render",r]]);export{k as __pageData,g as default};
